#!/usr/bin/env bash
set -euo pipefail
source "$(dirname "$0")/lib/common.sh"
serial=; cycles=6; package=org.archphene.linux.p0392be9c9f103a39d951c2f39c3644d2; while (($#)); do case "$1" in --serial) serial="${2:?}"; shift 2;; --cycles) cycles="${2:?}"; shift 2;; --package) package="${2:?}"; shift 2;; *) archphene_die "unknown argument: $1";; esac; done; [[ -n "$serial" ]] || archphene_die '--serial is required'; ((cycles>=1)) || archphene_die 'cycles must be at least 1'; archphene_init_adb "$serial"; activity="$(archphene_adb_run shell cmd package resolve-activity --brief -a android.intent.action.MAIN -c android.intent.category.LAUNCHER "$package" | tail -n1 | tr -d '\r')"; [[ "$activity" == */* ]] || archphene_die "could not resolve launcher activity for $package"
snapshot() { local pid="$1" targets; targets="$(archphene_adb_run shell run-as "$package" sh -c "'for f in /proc/$pid/fd/*; do readlink \$f; done'" 2>/dev/null)" || archphene_die 'could not inspect descriptors; install a debuggable build'; printf '%s|%s|%s|%s\n' "$(wc -l <<<"$targets")" "$(grep -c '/memfd:wayland-shm' <<<"$targets" || true)" "$(grep -c '^anon_inode:sync_file$' <<<"$targets" || true)" "$(grep -c '^/dev/ashmem' <<<"$targets" || true)"; }
old_acc="$(archphene_adb_run shell settings get system accelerometer_rotation | tr -d '\r')"; old_rot="$(archphene_adb_run shell settings get system user_rotation | tr -d '\r')"; restore(){ archphene_adb_run shell settings put system accelerometer_rotation "$old_acc" >/dev/null || true; archphene_adb_run shell settings put system user_rotation "$old_rot" >/dev/null || true; }; trap restore EXIT
archphene_adb_run shell settings put system accelerometer_rotation 0; archphene_adb_run shell settings put system user_rotation 0; archphene_adb_run shell am force-stop "$package"; archphene_adb_run shell am start -W -n "$activity" >/dev/null; sleep 8; pid="$(archphene_adb_run shell pidof "$package" | tr -d '\r')"; [[ -n "$pid" ]] || archphene_die 'KCalc process is not running'; before="$(snapshot "$pid")"; for ((i=1;i<=cycles;i++)); do archphene_adb_run shell settings put system user_rotation 1; sleep 0.9; archphene_adb_run shell settings put system user_rotation 0; sleep 0.9; done; sleep 15; after_pid="$(archphene_adb_run shell pidof "$package" | tr -d '\r')"; [[ "$after_pid" == "$pid" ]] || archphene_die "KCalc restarted during rotation: $pid -> $after_pid"; after="$(snapshot "$pid")"; IFS='|' read -r bt bw bs ba <<<"$before"; IFS='|' read -r at aw as aa <<<"$after"; ((aw<=bw+1)) || archphene_die "Wayland SHM descriptors leaked: $bw -> $aw"; archphene_note "KCalc FD lifecycle passed on $serial after $cycles cycles. Total: $bt -> $at; wayland-shm: $bw -> $aw; sync fences: $bs -> $as; ashmem: $ba -> $aa"
